// ===== SW-007 build() — METADATA from a BOUNDED FRONT-MATTER WINDOW =====
// Metadata (title, version, author, effective date) is DOCUMENT-LEVEL and lives in the front
// matter. Batching it would produce duplicate and CONFLICTING metadata (batch 7 has no title;
// batch 12 invents one) and burn tokens for nothing. So SW-007 does NOT batch: it sends a
// bounded window and makes ONE call.
//
// This is also a QUALITY improvement, not merely a token saving: sending the whole document and
// asking for the title invites the model to pick up spurious "metadata" from body text.
const incoming = $('When Executed by WF-001').first().json;
const prow = $('Load PR-002 + LLM Settings').first().json;
const s = prow.settings || {};
const sys = prow.system_prompt || '';

const metadataParagraphs = Number(s.metadataParagraphs ?? 80);   // R-08: authored config
const metadataScanPages  = Number(s.metadataScanPages ?? 5);
const reservedOutput     = Number(s.reservedOutputTokens ?? 4000);

const ocr = incoming.ocr || {};
const paras = ocr.paragraphs || [];

// Window = the first N paragraphs, PLUS every title/sectionHeading within the first M pages
// (headings carry version/scope information that may sit past the first N paragraphs).
const picked = new Map();
for (const p of paras.slice(0, metadataParagraphs)) picked.set(p.index, p);
for (const p of paras) {
  if (!p.role) continue;
  if (p.role !== 'title' && p.role !== 'sectionHeading') continue;
  // For paginated formats respect the page bound; for DOCX (page===null) take early headings only.
  const withinScan = (p.page != null) ? (p.page <= metadataScanPages)
                                      : (p.index <= metadataParagraphs * 4);
  if (withinScan) picked.set(p.index, p);
}
const window = Array.from(picked.values()).sort((a, b) => a.index - b.index);

const lines = [];
let lastPage = null;
for (const p of window) {
  if (p.page != null && p.page !== lastPage) { lines.push('=== PAGE ' + p.page + ' ==='); lastPage = p.page; }
  const loc = (p.page != null) ? ('p' + p.page + ':para' + p.index) : ('para' + p.index);
  const role = p.role ? (' (' + p.role + ')') : '';
  lines.push('[' + loc + ']' + role + ' ' + p.text);
}
const excerpt = lines.join('\n');

// PR-002 UNCHANGED — the {{ocr}} placeholder receives the front-matter window.
const usr = (prow.user_prompt || '').replace('{{ocr}}', excerpt);

const stats = {
  sourceFormat: ocr.sourceFormat || 'unknown',
  documentParagraphs: paras.length,
  windowParagraphs: window.length,
  headingsIncluded: window.filter(p => p.role).length,
  promptChars: usr.length,
  approxPromptTokens: Math.round(usr.length / 4),
};
console.log('[SW-007 front-matter window] ' + JSON.stringify(stats));

return [{ json: {
  _model: s.model,
  _temp:  s.temperature ?? 0,
  _max:   reservedOutput,
  _docStats: stats,
  messages: [ ...(sys ? [{ role: 'system', content: sys }] : []), { role: 'user', content: usr } ]
}}];

// Enrichment: preserve incoming item (incl. ocr for SW-008), add { metadata }.
const incoming = $('When Executed by WF-001').first().json;
const resp = $json;
const content = resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;
let parsed; try { parsed = JSON.parse(content); } catch(e){ parsed = { metadata: [] }; }
const metadata = Array.isArray(parsed) ? parsed : (parsed.metadata || []);
return [{ json: { ...incoming, metadata } }];
